/**
 * Set appliedBy to null for auto-generated holiday/week-off ODs (system-applied).
 * Use after deploying optional appliedBy on OD + autoODService using null appliedBy.
 *
 * Targets the same fingerprint as autoODService.js (purpose + place + remarks prefix).
 *
 * Usage (from backend/):
 *   node scripts/fixAutoODAppliedBy.js
 *   node scripts/fixAutoODAppliedBy.js --quiet
 *   node scripts/fixAutoODAppliedBy.js --apply
 */

const path = require('path');
const mongoose = require('mongoose');
require('dotenv').config({ path: path.join(__dirname, '../.env') });

const OD = require('../leaves/model/OD');

const APPLY = process.argv.includes('--apply');
const QUIET = process.argv.includes('--quiet');

const AUTO_OD_QUERY = {
  isActive: true,
  purpose: 'Work on Holiday/Week-off',
  placeVisited: 'Organization Campus (Auto)',
  remarks: { $regex: /^Auto-generated by system/i },
};

async function main() {
  const uri = process.env.MONGODB_URI;
  if (!uri) {
    console.error('MONGODB_URI is not set in backend/.env');
    process.exit(1);
  }

  await mongoose.connect(uri);
  console.log(APPLY ? 'Mode: APPLY' : 'Mode: DRY-RUN (pass --apply to write)');
  console.log('---');

  const candidates = await OD.find({
    ...AUTO_OD_QUERY,
    appliedBy: { $ne: null },
  })
    .select('_id emp_no appliedBy')
    .lean();

  if (!QUIET && candidates.length) {
    for (const c of candidates) {
      console.log(`[would clear appliedBy] OD ${c._id} emp=${c.emp_no} appliedBy=${c.appliedBy}`);
    }
  }

  console.log('---');
  console.log(`Auto-OD rows with non-null appliedBy: ${candidates.length}`);

  if (!APPLY || candidates.length === 0) {
    if (!APPLY && candidates.length) {
      console.log('\nRe-run with --apply to set appliedBy to null (system) on these rows.');
    }
    await mongoose.disconnect();
    process.exit(0);
  }

  let written = 0;
  for (const c of candidates) {
    const doc = await OD.findById(c._id);
    if (!doc || !doc.appliedBy) continue;

    const prev = doc.appliedBy;
    doc.appliedBy = null;

    if (!doc.workflow) doc.workflow = {};
    if (!Array.isArray(doc.workflow.history)) doc.workflow.history = [];

    doc.workflow.history.push({
      step: 'system',
      action: 'status_changed',
      actionBy: null,
      actionByName: 'Script: fixAutoODAppliedBy',
      actionByRole: 'system',
      comments: `appliedBy cleared (${String(prev)}); auto OD is system-applied.`,
      timestamp: new Date(),
    });

    await doc.save();
    written += 1;
    console.log(`Updated OD ${doc._id} — appliedBy set to null (was ${String(prev)})`);
  }

  console.log(`\nDone. Updated ${written} document(s).`);
  await mongoose.disconnect();
  process.exit(0);
}

main().catch((e) => {
  console.error(e);
  process.exit(1);
});
